import socket
from random import randint

# Game server settings
HOST = '127.0.0.1'
PORT = 12345
MAX_PLAYERS = 32

# Initialize game state
players = [{'id': i, 'x': randint(0, 100), 'y': randint(0, 100)} for i in range(MAX_PLAYERS)]

# Create socket and bind to address and port
server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
server_socket.bind((HOST, PORT))

# Listen for incoming connections
server_socket.listen(10)

print("Server listening on", HOST, ":", PORT)

# Function to broadcast game state
def broadcast_game_state():
    for player in players:
        data = str(player).encode()
        for client_socket in clients_sockets:
            if client_socket != server_socket:
                client_socket.send(data)

while True:
    # Wait for connections
    client_socket, address = server_socket.accept()

    print("New connection from", address)
    
    clients_sockets.append(client_socket)

    # Send game state to new player
    broadcast_game_state()

    while True:
        try:
            # Receive data from client (player movement)
            data = client_socket.recv(1024)
            if not data:
                break

            # Update player position and broadcast new game state
            for i, player in enumerate(players):
                if player['id'] == int(data.decode()):
                    players[i]['x'] += 1
                    players[i]['y'] += 1

            broadcast_game_state()

        except Exception as e:
            print("Error occurred:", str(e))
            break

    # Close client socket
    clients_sockets.remove(client_socket)
    client_socket.close()

# Handle incoming connections in another thread
import threading

clients_sockets = []
def handle_incoming_connections():
    global server_socket
    while True:
        client_socket, address = server_socket.accept()
        clients_sockets.append(client_socket)

threading.Thread(target=handle_incoming_connections).start()